// PrithviNet API Service Layer
const BASE = '/api';

function getToken() {
  return localStorage.getItem('prithvinet_token');
}

export async function api(method, path, body) {
  const headers = { 'Content-Type': 'application/json' };
  const token = getToken();
  if (token) headers['Authorization'] = `Bearer ${token}`;
  const opts = { method, headers };
  if (body) opts.body = JSON.stringify(body);
  try {
    const res = await fetch(`${BASE}${path}`, opts);
    const data = await res.json().catch(() => null);
    return { ok: res.ok, status: res.status, data };
  } catch (e) {
    return { ok: false, status: 0, data: { error: 'Connection refused — is the backend running?' } };
  }
}

// ─── AUTH ─────────────────────────────────────────────────
export const login = (email, password) => api('POST', '/auth/login', { email, password });
export const register = (name, email, password, role, extra = {}) => api('POST', '/auth/register', { name, email, password, role, ...extra });
export const getMe = () => api('GET', '/auth/me');

// ─── PUBLIC ───────────────────────────────────────────────
export const getOverview = () => api('GET', '/public/overview');
export const getRegionalOffices = () => api('GET', '/public/regional-offices');
export const getPublicAlerts = () => api('GET', '/public/alerts');
export const getMapData = (type) => api('GET', `/public/map-data/${type}`);
export const getTrend = (type, locationId, days = 7) => api('GET', `/public/trend/${type}/${locationId}?days=${days}`);

// ─── MONITORING DATA ──────────────────────────────────────
export const getMonitoringData = (type, limit = 10, locationId) => {
  let path = `/monitoring/${type}?limit=${limit}`;
  if (locationId) path += `&locationId=${locationId}`;
  return api('GET', path);
};
export const submitMonitoringData = (type, body) => api('POST', `/monitoring/${type}`, body);

// ─── MONITORING LOCATIONS ─────────────────────────────────
export const getMonitoringLocations = (type) => {
  let path = '/monitoring-locations';
  if (type) path += `?type=${type}`;
  return api('GET', path);
};
export const createMonitoringLocation = (body) => api('POST', '/monitoring-locations', body);

// ─── ALERTS ───────────────────────────────────────────────
export const getAlerts = (status, severity, limit = 20) => {
  let path = `/alerts?limit=${limit}`;
  if (status) path += `&status=${status}`;
  if (severity) path += `&severity=${severity}`;
  return api('GET', path);
};
export const acknowledgeAlert = (id) => api('PUT', `/alerts/${id}/acknowledge`, {});
export const resolveAlert = (id) => api('PUT', `/alerts/${id}/resolve`, {});

// ─── REGIONAL OFFICES (Admin) ─────────────────────────────
export const getOffices = () => api('GET', '/regional-offices');
export const createOffice = (body) => api('POST', '/regional-offices', body);
export const updateOffice = (id, body) => api('PUT', `/regional-offices/${id}`, body);
export const deleteOffice = (id) => api('DELETE', `/regional-offices/${id}`);

// ─── INDUSTRIES (Admin) ──────────────────────────────────
export const getIndustries = (status) => {
  let path = '/industries';
  if (status) path += `?status=${status}`;
  return api('GET', path);
};
export const createIndustry = (body) => api('POST', '/industries', body);
export const updateIndustry = (id, body) => api('PUT', `/industries/${id}`, body);

// ─── WATER SOURCES (Admin) ────────────────────────────────
export const getWaterSources = () => api('GET', '/water-sources');
export const createWaterSource = (body) => api('POST', '/water-sources', body);

// ─── PRESCRIBED LIMITS & UNITS ────────────────────────────
export const getPrescribedLimits = () => api('GET', '/prescribed-limits');
export const getMonitoringUnits = () => api('GET', '/monitoring-units');

import React, { useState } from 'react';
import { Map as MapIcon, LayoutDashboard, Activity, AlertTriangle, Settings, User, Bell, Search, ChevronDown } from 'lucide-react';
import MonitoringCards from './MonitoringCards';
import PollutionMap from './PollutionMap';
import ForecastCharts from './ForecastCharts';
import AlertsPanel from './AlertsPanel';



const Dashboard = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [location, setLocation] = useState('Chhattisgarh (State Overview)');

  return (
    <div className="layout">
      {/* Sidebar Navigation */}
      <aside className="sidebar">
        <div className="logo-container" style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '48px' }}>
          <div style={{ width: '40px', height: '40px', background: 'linear-gradient(135deg, #10b981, #059669)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 0 20px rgba(16,185,129,0.3)' }}>
            <Activity size={24} color="white" />
          </div>
          <h1 className="glow-text" style={{ fontSize: '1.5rem', fontWeight: 700, margin: 0, letterSpacing: '1px' }}>Prithvi<span style={{ color: '#10b981' }}>Net</span></h1>
        </div>

        <nav style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          <NavItem icon={<LayoutDashboard size={20} />} label="Overview" active={activeTab === 'overview'} onClick={() => setActiveTab('overview')} />
          <NavItem icon={<MapIcon size={20} />} label="Pollution Map" active={activeTab === 'map'} onClick={() => setActiveTab('map')} />
          <NavItem icon={<Activity size={20} />} label="Forecasting" active={activeTab === 'forecast'} onClick={() => setActiveTab('forecast')} />
          <NavItem icon={<AlertTriangle size={20} />} label="Alerts & Disruption" badge="3" active={activeTab === 'alerts'} onClick={() => setActiveTab('alerts')} />
        </nav>

        <div style={{ marginTop: 'auto' }}>
          <div className="glass-panel" style={{ padding: '16px', borderRadius: '12px', background: 'rgba(59, 130, 246, 0.1)', borderColor: 'rgba(59, 130, 246, 0.2)' }}>
            <h4 style={{ color: '#60a5fa', marginBottom: '8px', fontSize: '0.875rem' }}>AI Compliance Copilot</h4>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.75rem', marginBottom: '12px' }}>Simulate interventions and forecast impact.</p>
            <button style={{ background: '#3b82f6', color: 'white', padding: '8px 16px', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 600, width: '100%', transition: 'background 0.2s' }}>Open Copilot</button>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="main-content">
        {/* Header */}
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', width: '100%' }}>
          <div>
            <h2 style={{ fontSize: '1.75rem', margin: '0 0 4px 0' }}>Public Dashboard</h2>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', margin: 0 }}>Real-time environmental monitoring & transparency portal</p>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <div className="glass-panel" style={{ display: 'flex', alignItems: 'center', padding: '8px 16px', borderRadius: '20px', gap: '12px', cursor: 'pointer', background: 'rgba(255,255,255,0.03)' }}>
              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#10b981', boxShadow: '0 0 8px #10b981' }}></div>
              <span style={{ fontSize: '0.9rem', color: 'var(--text-primary)', fontWeight: 500 }}>{location}</span>
              <ChevronDown size={14} color="var(--text-secondary)" />
            </div>

            <button className="glass-panel" style={{ width: '40px', height: '40px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative' }}>
              <Bell size={18} color="var(--text-primary)" />
              <span style={{ position: 'absolute', top: '8px', right: '10px', width: '8px', height: '8px', background: '#ef4444', borderRadius: '50%' }}></span>
            </button>
            <button className="glass-panel" style={{ width: '40px', height: '40px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <User size={18} color="var(--text-primary)" />
            </button>
          </div>
        </header>

        {/* Dashboard Content */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '24px', overflowY: 'auto', paddingRight: '8px' }}>
          {activeTab === 'overview' && (
             <MonitoringCards />
          )}
          
          {activeTab === 'map' && (
             <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: '600px' }}>
                <PollutionMap />
             </div>
          )}

          {activeTab === 'forecast' && (
             <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: '500px' }}>
                <ForecastCharts />
             </div>
          )}

          {activeTab === 'alerts' && (
             <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: '500px' }}>
                <AlertsPanel />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

// Nav Item Component
const NavItem = ({ icon, label, active, onClick, badge }) => {
  return (
    <button
      onClick={onClick}
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: '12px',
        padding: '12px 16px',
        borderRadius: '12px',
        color: active ? '#10b981' : 'var(--text-secondary)',
        background: active ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: `1px solid ${active ? 'rgba(16, 185, 129, 0.2)' : 'transparent'}`,
        transition: 'all 0.2s',
        textAlign: 'left',
        width: '100%'
      }}
    >
      {icon}
      <span style={{ fontWeight: 500, fontSize: '0.95rem' }}>{label}</span>
      {badge && (
        <span style={{ marginLeft: 'auto', background: '#ef4444', color: 'white', fontSize: '0.7rem', fontWeight: 700, padding: '2px 6px', borderRadius: '10px' }}>
          {badge}
        </span>
      )}
    </button>
  );
};

export default Dashboard;

