import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Circle, useMap } from 'react-leaflet';
import { useNavigate } from 'react-router-dom';
import L from 'leaflet';
import 'leaflet.heat';
import { Info, Wind, Droplets, Volume2, Map as MapIcon, Building2, Factory, MapPin, ChevronLeft, ChevronRight, Layers } from 'lucide-react';
import { getMapData } from '../api';
import { REGIONS, REGION_DETAILS, MOCK_INDUSTRIES, MOCK_STATIONS, getComplianceColor, getComplianceLabel, getRiskLevel } from '../mockData';

const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

/* ────────── Icon factories ────────── */
const regionIcon = (color, score) => L.divIcon({
  className: '',
  html: `<div style="
    background:${color};border:3px solid rgba(255,255,255,0.9);color:#fff;
    border-radius:50%;width:52px;height:52px;display:flex;align-items:center;justify-content:center;
    font-weight:800;font-size:13px;font-family:system-ui;
    box-shadow:0 0 24px ${color}90,0 0 48px ${color}40;cursor:pointer;
    text-shadow:0 1px 3px rgba(0,0,0,0.5);
  ">${score}%</div>`,
  iconSize: [52, 52], iconAnchor: [26, 26], popupAnchor: [0, -26]
});

const factoryPin = (compliant) => L.divIcon({
  className: '',
  html: `<div style="
    background:${compliant ? 'rgba(16,185,129,0.85)' : 'rgba(239,68,68,0.85)'};
    border:2px solid rgba(255,255,255,0.8);border-radius:8px;width:30px;height:30px;
    display:flex;align-items:center;justify-content:center;font-size:16px;
    box-shadow:0 2px 8px ${compliant ? 'rgba(16,185,129,0.5)' : 'rgba(239,68,68,0.5)'};
  ">🏭</div>`,
  iconSize: [30, 30], iconAnchor: [15, 15], popupAnchor: [0, -15]
});

const stationPin = (type) => {
  const c = type === 'AIR' ? '#10b981' : type === 'WATER' ? '#3b82f6' : '#ef4444';
  return L.divIcon({
    className: '',
    html: `<div style="
      background:${c};border:2px solid rgba(255,255,255,0.8);border-radius:50%;width:26px;height:26px;
      display:flex;align-items:center;justify-content:center;font-size:13px;
      box-shadow:0 2px 8px ${c}60;
    ">📍</div>`,
    iconSize: [26, 26], iconAnchor: [13, 13], popupAnchor: [0, -13]
  });
};

/* ────────── Heatmap Layer Component ────────── */
const HeatmapLayer = ({ points }) => {
  const map = useMap();
  const heatRef = useRef(null);

  useEffect(() => {
    if (heatRef.current) { map.removeLayer(heatRef.current); }

    if (points.length === 0) return;

    // Each point: [lat, lng, intensity]
    heatRef.current = L.heatLayer(points, {
      radius: 60,
      blur: 45,
      maxZoom: 10,
      max: 1.0,
      minOpacity: 0.25,
      gradient: {
        0.0: '#10b981',   // green  – excellent
        0.25: '#34d399',
        0.4: '#fbbf24',   // yellow – moderate
        0.55: '#f59e0b',
        0.7: '#ef4444',   // red    – poor
        0.85: '#dc2626',
        1.0: '#991b1b'    // dark red – severe
      }
    }).addTo(map);

    return () => {
      if (heatRef.current) { map.removeLayer(heatRef.current); }
    };
  }, [map, points]);

  return null;
};

/* ────────── Main Component ────────── */
const PollutionMap = () => {
  const [activeTab, setActiveTab] = useState('air');
  const [mapData, setMapData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showIndustries, setShowIndustries] = useState(true);
  const [showStations, setShowStations] = useState(true);
  const [showRegions, setShowRegions] = useState(true);
  const [showHeatmap, setShowHeatmap] = useState(true);
  const [monthIndex, setMonthIndex] = useState(new Date().getMonth());
  const navigate = useNavigate();

  useEffect(() => {
    setLoading(true);
    getMapData(activeTab).then(res => {
      if (res.ok) setMapData(res.data);
      else setMapData([]);
      setLoading(false);
    }).catch(() => { setMapData([]); setLoading(false); });
  }, [activeTab]);

  /* Build heatmap point data with real blending between regions */
  const heatPoints = React.useMemo(() => {
    const pts = [];

    // Core region compliance points (inverted: 100% = low heat, 0% = max heat)
    REGIONS.forEach(r => {
      const intensity = 1 - (r.compliance / 100); // invert so poor compliance is hotter
      // Multiple concentric points for smooth blending
      for (let ring = 0; ring < 5; ring++) {
        const radius = ring * 0.08;
        const count = ring === 0 ? 1 : ring * 6;
        for (let i = 0; i < count; i++) {
          const angle = (2 * Math.PI * i) / count;
          const lat = r.lat + radius * Math.cos(angle) + (Math.random() - 0.5) * 0.03;
          const lng = r.lng + radius * Math.sin(angle) + (Math.random() - 0.5) * 0.03;
          const falloff = 1 - (ring / 5) * 0.6;
          pts.push([lat, lng, intensity * falloff]);
        }
      }
    });

    // Add pollution hotspot points from industries
    MOCK_INDUSTRIES.forEach(ind => {
      if (!ind.compliant) {
        const intensity = Math.min(1, ind.violations / 12);
        pts.push([ind.lat, ind.lng, intensity]);
        // Spread around it
        for (let i = 0; i < 4; i++) {
          pts.push([
            ind.lat + (Math.random() - 0.5) * 0.05,
            ind.lng + (Math.random() - 0.5) * 0.05,
            intensity * 0.6
          ]);
        }
      }
    });

    // Interpolation: add intermediate points between nearby regions for smooth blending
    for (let i = 0; i < REGIONS.length; i++) {
      for (let j = i + 1; j < REGIONS.length; j++) {
        const r1 = REGIONS[i], r2 = REGIONS[j];
        const dist = Math.sqrt((r1.lat - r2.lat) ** 2 + (r1.lng - r2.lng) ** 2);
        if (dist < 2.5) { // Only blend nearby regions
          const steps = Math.ceil(dist / 0.3);
          for (let s = 1; s < steps; s++) {
            const t = s / steps;
            const lat = r1.lat + (r2.lat - r1.lat) * t;
            const lng = r1.lng + (r2.lng - r1.lng) * t;
            const int1 = 1 - (r1.compliance / 100);
            const int2 = 1 - (r2.compliance / 100);
            const blended = int1 * (1 - t) + int2 * t;
            pts.push([lat, lng, blended * 0.5]);
            // Add slight scatter for smoothness
            pts.push([lat + (Math.random() - 0.5) * 0.08, lng + (Math.random() - 0.5) * 0.08, blended * 0.35]);
          }
        }
      }
    }

    return pts;
  }, []);

  return (
    <div className="glass-panel" style={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <div style={{ padding: '12px 20px', borderBottom: '1px solid var(--glass-border)', display: 'flex', gap: '12px', alignItems: 'center', flexWrap: 'wrap' }}>
        <h3 style={{ fontSize: '1rem', marginRight: 'auto', display: 'flex', alignItems: 'center', gap: '8px', margin: 0 }}>
          <MapIcon size={18} color="var(--accent-primary)" />
          Chhattisgarh Pollution & Compliance Map
        </h3>

        <div style={{ display: 'flex', background: 'rgba(0,0,0,0.3)', padding: '3px', borderRadius: '10px' }}>
          <TabBtn active={activeTab === 'air'} onClick={() => setActiveTab('air')} icon={<Wind size={14} />} label="Air" color="#10b981" />
          <TabBtn active={activeTab === 'water'} onClick={() => setActiveTab('water')} icon={<Droplets size={14} />} label="Water" color="#3b82f6" />
          <TabBtn active={activeTab === 'noise'} onClick={() => setActiveTab('noise')} icon={<Volume2 size={14} />} label="Noise" color="#ef4444" />
        </div>

        <div style={{ display: 'flex', gap: '5px' }}>
          <LayerToggle label="Heatmap" active={showHeatmap} onClick={() => setShowHeatmap(!showHeatmap)} icon="🌡️" />
          <LayerToggle label="Regions" active={showRegions} onClick={() => setShowRegions(!showRegions)} />
          <LayerToggle label="Industries" active={showIndustries} onClick={() => setShowIndustries(!showIndustries)} />
          <LayerToggle label="Stations" active={showStations} onClick={() => setShowStations(!showStations)} />
        </div>
      </div>

      {/* Map */}
      <div style={{ flex: 1, position: 'relative' }}>
        {loading && (
          <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, background: 'rgba(0,0,0,0.4)' }}>
            <span className="spinner"></span>
          </div>
        )}
        <MapContainer center={[21.5, 82.0]} zoom={7} style={{ height: '100%', width: '100%', background: '#0a0f1c' }} zoomControl={false}>
          <TileLayer
            url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
            attribution='&copy; OpenStreetMap &copy; CARTO'
          />

          {/* ── Real Heatmap Layer ── */}
          {showHeatmap && <HeatmapLayer points={heatPoints} />}

          {/* ── Region compliance markers ── */}
          {showRegions && REGIONS.map(region => {
            const color = getComplianceColor(region.compliance);
            const detail = REGION_DETAILS[region.id];
            return (
              <Marker key={region.id} position={[region.lat, region.lng]}
                icon={regionIcon(color, region.compliance)}
                eventHandlers={{ click: () => navigate(`/region/${region.id}`) }}>
                <Popup className="custom-popup" maxWidth={340}>
                  <div style={{ background: '#0f1523', color: 'white', padding: '18px', borderRadius: '12px', minWidth: '300px', boxShadow: '0 8px 32px rgba(0,0,0,0.5)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px' }}>
                      <div>
                        <h3 style={{ margin: '0 0 3px', fontSize: '1.05rem', fontWeight: 700
                        }}>{region.name} Regional Zone</h3>
                        <p style={{ margin: 0, fontSize: '0.75rem', color: '#64748b' }}>{region.district} District</p>
                      </div>
                      <span style={{ padding: '4px 12px', borderRadius: '12px', fontSize: '0.75rem', fontWeight: 700,
                        background: `${color}20`, color, border: `1px solid ${color}40` }}>
                        {region.compliance}%
                      </span>
                    </div>

                    <div style={{ display: 'flex', gap: '6px', marginBottom: '14px' }}>
                      <span style={{ fontSize: '0.7rem', padding: '3px 10px', borderRadius: '8px', background: `${color}15`, color, fontWeight: 600 }}>{getComplianceLabel(region.compliance)}</span>
                      <span style={{ fontSize: '0.7rem', padding: '3px 10px', borderRadius: '8px', background: 'rgba(255,255,255,0.06)', color: '#94a3b8', fontWeight: 600 }}>Risk: {getRiskLevel(region.compliance)}</span>
                    </div>

                    {detail && <>
                      <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: '12px', marginBottom: '12px' }}>
