    iconSize: [24, 24], iconAnchor: [12, 12], popupAnchor: [0, -12]
  });
};

const RegionDashboard = () => {
  const { user } = useAuth();
  const [trendType, setTrendType] = useState('air');
  const [showManageModal, setShowManageModal] = useState(null); // 'station' | 'industry' | null
  const [form, setForm] = useState({});
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  const u = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const [realIndustries, setRealIndustries] = useState([]);
  const [realStations, setRealStations] = useState([]);
  const [realAlerts, setRealAlerts] = useState([]);

  // For regional officers, use their assigned region. Fallback to Raipur for demo.
  const regionId = user?.region?.id || 'raipur';
  const regionName = user?.region?.name || 'Raipur';
  const region = REGIONS.find(r => r.id === regionId || r.name === regionName) || REGIONS[0];
  const detail = REGION_DETAILS[region.id] || REGION_DETAILS.raipur;
  const color = getComplianceColor(region.compliance);
  const trendData = genTrend();

  React.useEffect(() => {
    import('../api').then(({ getIndustries, getMonitoringLocations, getAlerts }) => {
      // Fetch industries
      getIndustries().then(res => {
        if (res.ok) {
          const regional = res.data.filter(ind => ind.regionId === region.id);
          setRealIndustries(regional);
        }
      });
      // Fetch stations
      getMonitoringLocations().then(res => {
        if (res.ok) {
          const regional = res.data.filter(st => st.regionId === region.id);
          setRealStations(regional);
        }
      });
      // Fetch alerts
      getAlerts('ACTIVE').then(res => {
        if (res.ok) {
          const regional = res.data.filter(a => a.location?.region?.name === region.name || a.regionId === region.id);
          setRealAlerts(regional);
        }
      });
    });
  }, [region.id, region.name]);

  const industries = realIndustries.map(ind => ({
    id: ind.id,
    name: ind.name,
    type: ind.type,
    lat: ind.lat,
    lng: ind.lng,
    region: region.name,
    compliant: ind.status === 'ACTIVE',
    violations: 0,
    status: ind.status
  }));

  const stations = realStations;
  const alerts = realAlerts;

  const updateIndStatus = async (id, status, text) => {
    import('../api').then(async ({ updateIndustry }) => {
      const res = await updateIndustry(id, { status });
      if (res.ok) {
        setRealIndustries(prev => prev.map(ind => ind.id === id ? { ...ind, status } : ind));
        alert(text);
      } else {
        alert('Failed to update industry status.');
      }
    });
  };

  const handleApprove = (id) => updateIndStatus(id, 'ACTIVE', 'Industry approved.');
  const handleReject = (id) => updateIndStatus(id, 'INACTIVE', 'Industry rejected.');
  const handleSuspend = (id) => updateIndStatus(id, 'SUSPENDED', 'Industry suspended.');

  const handleCreate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError('');
    
    const baseBody = {
      name: form.name,
      type: form.type || (showManageModal === 'station' ? 'AIR' : ''),
      lat: parseFloat(form.lat),
      lng: parseFloat(form.lng),
      regionId
    };

    let r;
    if (showManageModal === 'industry') {
      r = await createIndustry({ ...baseBody, registrationNo: form.registrationNo });
    } else {
      r = await createMonitoringLocation(baseBody);
    }
    
    setSaving(false);
    if (r.ok) {
      setShowManageModal(null);
      // Here we would typically refresh data from API, but for demo we just close modal
      alert(`Successfully created ${showManageModal}. It is now pending admin approval.`);
    } else {
      setError(r.data?.error || 'Failed to create');
    }
  };

  const openManageModal = (type) => {
    setForm({ name: '', type: type === 'station' ? 'AIR' : '', lat: '', lng: '', registrationNo: '' });
    setError('');
    setShowManageModal(type);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', width: '100%' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h2 style={{ fontSize: '1.5rem', margin: '0 0 4px' }}>My Region: {region.name}</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', margin: 0 }}>Regional Officer Dashboard — {region.district} District</p>
        </div>
        <div style={{ display: 'flex', gap: '10px' }}>
          <span className={`status-badge ${region.compliance >= 80 ? 'status-good' : region.compliance >= 60 ? 'status-moderate' : 'status-poor'}`}>
            Compliance: {region.compliance}%
          </span>
        </div>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '12px' }}>
        <MiniStat icon={<Factory size={18} />} label="Industries" value={detail.industries.total} color="#3b82f6" />
        <MiniStat icon={<CheckCircle size={18} />} label="Compliant" value={detail.industries.compliant} color="#10b981" />
        <MiniStat icon={<XCircle size={18} />} label="Non-Compliant" value={detail.industries.nonCompliant} color="#ef4444" />
        <MiniStat icon={<MapPin size={18} />} label="Stations" value={detail.stations} color="#f59e0b" />
        <MiniStat icon={<AlertTriangle size={18} />} label="Active Alerts" value={alerts.length} color="#ef4444" />
      </div>

      {/* Map + Alerts */}
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '16px', minHeight: '340px' }}>
        <div className="glass-panel" style={{ overflow: 'hidden' }}>
          <MapContainer center={[region.lat, region.lng]} zoom={11} style={{ height: '100%', width: '100%', background: '#0a0f1c' }} zoomControl={false}>
            <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />
            <Circle center={[region.lat, region.lng]} radius={20000}
              pathOptions={{ color: 'transparent', fillColor: color, fillOpacity: 0.1 }} />
            {stations.map(s => (
              <Marker key={s.id} position={[s.lat, s.lng]} icon={stationPinIcon(s.type)}>
                <Popup><div style={{ background: '#0f1523', color: 'white', padding: '10px', borderRadius: '8px' }}><b>{s.name}</b></div></Popup>
              </Marker>
            ))}
            {industries.map(i => (
              <Marker key={i.id} position={[i.lat, i.lng]} icon={factoryIcon(i.compliant)}>
                <Popup><div style={{ background: '#0f1523', color: 'white', padding: '10px', borderRadius: '8px' }}><b>{i.name}</b><br /><span style={{ color: i.compliant ? '#10b981' : '#ef4444', fontSize: '12px' }}>{i.compliant ? '✓ Compliant' : '✗ Non-compliant'}</span></div></Popup>
              </Marker>
            ))}
          </MapContainer>
        </div>

        <div className="glass-panel" style={{ padding: '16px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          <h3 style={{ fontSize: '0.95rem', margin: '0 0 12px', display: 'flex', alignItems: 'center', gap: '6px' }}>
            <AlertTriangle size={16} color="#ef4444" /> Region Alerts
          </h3>
          <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {alerts.length === 0 ? (
              <p style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px' }}>No active alerts ✅</p>
            ) : alerts.map(a => (
              <div key={a.id} style={{ padding: '10px', borderRadius: '8px', background: 'rgba(255,255,255,0.03)', borderLeft: `3px solid ${a.severity === 'CRITICAL' ? '#ef4444' : a.severity === 'WARNING' ? '#fbbf24' : '#3b82f6'}` }}>
                <p style={{ margin: '0 0 2px', fontSize: '0.82rem', fontWeight: 600 }}>{a.parameter}</p>
                <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{a.message.substring(0, 80)}…</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Trend Chart */}
      <div className="glass-panel" style={{ padding: '20px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
          <h3 style={{ fontSize: '1rem', margin: 0 }}>30-Day Pollution Trends</h3>
          <div style={{ display: 'flex', gap: '4px', background: 'rgba(0,0,0,0.2)', padding: '3px', borderRadius: '10px' }}>
            {[{ k: 'air', l: 'Air', c: '#10b981' }, { k: 'water', l: 'Water', c: '#3b82f6' }, { k: 'noise', l: 'Noise', c: '#ef4444' }].map(t => (
              <button key={t.k} onClick={() => setTrendType(t.k)} style={{
                padding: '5px 10px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 600,
                background: trendType === t.k ? `${t.c}20` : 'transparent',
                color: trendType === t.k ? t.c : 'var(--text-muted)', border: 'none'
              }}>{t.l}</button>
            ))}
          </div>
        </div>
        <div style={{ height: '200px' }}>
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={trendData}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
              <XAxis dataKey="day" stroke="rgba(255,255,255,0.3)" fontSize={10} />
              <YAxis stroke="rgba(255,255,255,0.3)" fontSize={10} />
              <Tooltip contentStyle={{ background: 'rgba(10,15,25,0.95)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: '8px', color: 'white' }} />
              <Area type="monotone" dataKey={trendType === 'air' ? 'aqi' : trendType === 'water' ? 'ph' : 'noise'}
                stroke={trendType === 'air' ? '#10b981' : trendType === 'water' ? '#3b82f6' : '#ef4444'} strokeWidth={2}
                fill={trendType === 'air' ? '#10b98115' : trendType === 'water' ? '#3b82f615' : '#ef444415'} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Management Actions */}
      {user?.role === 'REGIONAL_OFFICER' && (
        <div style={{ display: 'flex', gap: '12px' }}>
          <button className="action-btn primary-btn" onClick={() => openManageModal('station')}>
            <Plus size={16} /> Add Monitoring Station
          </button>
          <button className="action-btn primary-btn" onClick={() => openManageModal('industry')} style={{ background: 'linear-gradient(135deg, #3b82f6, #2563eb)' }}>
            <Plus size={16} /> Add Industry
          </button>
        </div>
      )}

      {/* Industries Table */}
      <div className="glass-panel" style={{ overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--glass-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h3 style={{ fontSize: '0.95rem', margin: 0 }}>Industries ({industries.length})</h3>
        </div>
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead><tr><th></th><th>Name</th><th>Type</th><th>Violations</th><th>Status</th>{user?.role === 'REGIONAL_OFFICER' && <th>Actions</th>}</tr></thead>
            <tbody>
              {industries.map(ind => (
                <tr key={ind.id}>
                  <td><div style={{ width: '8px', height: '8px', borderRadius: '50%', background: ind.compliant ? '#10b981' : '#ef4444' }} /></td>
                  <td style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{ind.name}</td>
                  <td>{ind.type}</td>
                  <td style={{ color: ind.violations > 0 ? '#ef4444' : '#10b981' }}>{ind.violations}</td>
                  <td><span className={`status-badge ${ind.compliant ? 'status-good' : 'status-poor'}`} style={{ fontSize: '0.7rem' }}>{ind.compliant ? 'Compliant' : 'Non-compliant'}</span></td>
                  {user?.role === 'REGIONAL_OFFICER' && (
                    <td>
                      <div style={{ display: 'flex', gap: '6px' }}>
                        {ind.status === 'PENDING' && (
                          <>
                            <button onClick={() => handleApprove(ind.id)} className="action-btn primary-btn" style={{ padding: '4px 10px', fontSize: '0.75rem', height: 'auto', background: '#3b82f6' }}>Approve</button>
                            <button onClick={() => handleReject(ind.id)} className="action-btn primary-btn" style={{ padding: '4px 10px', fontSize: '0.75rem', height: 'auto', background: '#ef4444' }}>Reject</button>
                          </>
                        )}
                        {ind.status === 'ACTIVE' && (
                          <button onClick={() => handleSuspend(ind.id)} className="action-btn primary-btn" style={{ padding: '4px 10px', fontSize: '0.75rem', height: 'auto', background: '#f59e0b' }}>Suspend</button>
                        )}
                        {ind.status === 'SUSPENDED' && (
                          <button onClick={() => handleApprove(ind.id)} className="action-btn primary-btn" style={{ padding: '4px 10px', fontSize: '0.75rem', height: 'auto', background: '#3b82f6' }}>Re-activate</button>
                        )}
                      </div>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Manage Modal */}
      {showManageModal && (
        <div className="modal-overlay" onClick={() => setShowManageModal(null)}>
          <div className="modal glass-panel" onClick={e => e.stopPropagation()}>
            <h3 style={{ marginBottom: '16px' }}>Add {showManageModal === 'station' ? 'Monitoring Station' : 'Industry'}</h3>
            {error && <div className="auth-error" style={{ marginBottom: '12px' }}>{error}</div>}
            <form onSubmit={handleCreate}>
              <div className="modal-fields">
                <div><label>Name</label><input value={form.name} onChange={e => u('name', e.target.value)} required placeholder={`Enter ${showManageModal} name`} /></div>
                <div><label>Type</label>
                  {showManageModal === 'station' ? (
                    <select value={form.type} onChange={e => u('type', e.target.value)} required>
                      <option value="AIR">AIR</option>
                      <option value="WATER">WATER</option>
                      <option value="NOISE">NOISE</option>
                    </select>
                  ) : (
                    <input value={form.type} onChange={e => u('type', e.target.value)} required placeholder="e.g. Steel, Cement, Chemical" />
                  )}
                </div>
                <div><label>Latitude</label><input type="number" step="any" value={form.lat} onChange={e => u('lat', e.target.value)} required placeholder="e.g. 21.2514" /></div>
                <div><label>Longitude</label><input type="number" step="any" value={form.lng} onChange={e => u('lng', e.target.value)} required placeholder="e.g. 81.6296" /></div>
                {showManageModal === 'industry' && <div><label>Registration No.</label><input value={form.registrationNo} onChange={e => u('registrationNo', e.target.value)} required placeholder="e.g. CG-STL-001" /></div>}
              </div>
              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button type="submit" className="action-btn primary-btn" disabled={saving} style={{ flex: 1 }}>{saving ? <span className="spinner"></span> : 'Create'}</button>
                <button type="button" className="action-btn" onClick={() => setShowManageModal(null)} style={{ flex: 1, background: 'rgba(255,255,255,0.05)', color: 'var(--text-secondary)', border: '1px solid var(--glass-border)' }}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const MiniStat = ({ icon, label, value, color }) => (
  <div className="glass-panel" style={{ padding: '14px', display: 'flex', alignItems: 'center', gap: '10px' }}>
    <div style={{ width: '36px', height: '36px', borderRadius: '10px', background: `${color}12`, border: `1px solid ${color}25`, display: 'flex', alignItems: 'center', justifyContent: 'center', color }}>{icon}</div>
    <div>
      <p style={{ fontSize: '0.7rem', color: 'var(--text-muted)', margin: '0 0 1px' }}>{label}</p>
      <p style={{ fontSize: '1.1rem', fontWeight: 700, margin: 0, fontFamily: 'var(--font-display)' }}>{value}</p>
    </div>
  </div>
);

export default RegionDashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getRegionalOffices } from '../api';
import { UserPlus, Mail, Lock, User, Activity, ChevronDown, Factory, MapPin, FileText } from 'lucide-react';

const ROLES = ['CITIZEN', 'INDUSTRY_USER', 'MONITORING_TEAM', 'REGIONAL_OFFICER', 'SUPER_ADMIN'];

export default function RegisterPage() {
  const { registerUser } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'CITIZEN' });
  const [industryForm, setIndustryForm] = useState({ industryName: '', industryType: '', registrationNo: '', lat: '', lng: '', industryRegionId: '' });
  const [regions, setRegions] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const update = (key, val) => setForm(f => ({ ...f, [key]: val }));
  const updateInd = (key, val) => setIndustryForm(f => ({ ...f, [key]: val }));

  const isIndustry = form.role === 'INDUSTRY_USER';

  // Fetch regions for the dropdown
  useEffect(() => {
    if (isIndustry && regions.length === 0) {
      getRegionalOffices().then(r => { if (r.ok) setRegions(r.data); });
    }
  }, [isIndustry]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);

    const extra = isIndustry ? {
      industryName: industryForm.industryName,
      industryType: industryForm.industryType,
      registrationNo: industryForm.registrationNo,
      lat: parseFloat(industryForm.lat),
      lng: parseFloat(industryForm.lng),
      industryRegionId: industryForm.industryRegionId
    } : {};

    const res = await registerUser(form.name, form.email, form.password, form.role, extra);
    setLoading(false);
    if (res.ok) navigate('/dashboard');
    else setError(res.data?.error || 'Registration failed');
  };

  return (
    <div className="auth-page">
      <div className="auth-container">
        <div className="auth-card glass-panel">
          <div className="auth-logo">
            <div className="auth-logo-icon">
              <Activity size={28} color="white" />
            </div>
            <h1 className="glow-text" style={{ fontSize: '1.8rem', margin: 0 }}>
              Prithvi<span style={{ color: '#10b981' }}>Net</span>
            </h1>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', margin: '4px 0 0' }}>Create your account</p>
          </div>

          {error && <div className="auth-error">{error}</div>}

          <form onSubmit={handleSubmit}>
            <div className="input-group">
              <User size={16} className="input-icon" />
              <input type="text" placeholder="Full Name" value={form.name} onChange={e => update('name', e.target.value)} required />
            </div>
            <div className="input-group">
              <Mail size={16} className="input-icon" />
              <input type="email" placeholder="Email address" value={form.email} onChange={e => update('email', e.target.value)} required />
            </div>
            <div className="input-group">
              <Lock size={16} className="input-icon" />
              <input type="password" placeholder="Password (min 6 chars)" value={form.password} onChange={e => update('password', e.target.value)} required minLength={6} />
            </div>
            <div className="input-group">
              <ChevronDown size={16} className="input-icon" />
              <select value={form.role} onChange={e => update('role', e.target.value)}>
                {ROLES.map(r => <option key={r} value={r}>{r.replace(/_/g, ' ')}</option>)}
              </select>
            </div>

            {/* Industry fields — only when INDUSTRY_USER is selected */}
            {isIndustry && (
              <div style={{ padding: '16px', marginTop: '8px', borderRadius: '12px', border: '1px solid rgba(59,130,246,0.25)', background: 'rgba(59,130,246,0.05)' }}>
                <p style={{ margin: '0 0 12px', fontSize: '0.8rem', fontWeight: 600, color: '#3b82f6', display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <Factory size={14} /> Industry Details (submitted for approval)
                </p>
                <div className="input-group">
                  <Factory size={16} className="input-icon" />
                  <input placeholder="Industry Name" value={industryForm.industryName} onChange={e => updateInd('industryName', e.target.value)} required />
                </div>
                <div className="input-group">
                  <FileText size={16} className="input-icon" />
                  <input placeholder="Type (e.g. Steel, Chemical)" value={industryForm.industryType} onChange={e => updateInd('industryType', e.target.value)} required />
                </div>
                <div className="input-group">
                  <FileText size={16} className="input-icon" />
                  <input placeholder="Registration No. (e.g. CG-STL-001)" value={industryForm.registrationNo} onChange={e => updateInd('registrationNo', e.target.value)} required />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                  <div className="input-group">
                    <MapPin size={16} className="input-icon" />
                    <input type="number" step="any" placeholder="Latitude" value={industryForm.lat} onChange={e => updateInd('lat', e.target.value)} required />
                  </div>
                  <div className="input-group">
                    <MapPin size={16} className="input-icon" />
                    <input type="number" step="any" placeholder="Longitude" value={industryForm.lng} onChange={e => updateInd('lng', e.target.value)} required />
                  </div>
                </div>
                <div className="input-group">
                  <ChevronDown size={16} className="input-icon" />
                  <select value={industryForm.industryRegionId} onChange={e => updateInd('industryRegionId', e.target.value)} required>
                    <option value="">Select Region</option>
                    {regions.map(r => <option key={r.id} value={r.id}>{r.name} — {r.district}</option>)}
                  </select>
                </div>
              </div>
            )}

            <button type="submit" className="auth-submit" disabled={loading} style={{ marginTop: '16px' }}>
              {loading ? <span className="spinner"></span> : <><UserPlus size={16} /> {isIndustry ? 'Register & Submit for Approval' : 'Create Account'}</>}
            </button>
          </form>

          <p style={{ textAlign: 'center', fontSize: '0.85rem', color: 'var(--text-secondary)', marginTop: '20px' }}>
            Already have an account? <Link to="/login" style={{ color: '#10b981', fontWeight: 600 }}>Sign In</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

